import{_ as a,c as e,o as n,ag as c}from"./chunks/framework.DnwzncJk.js";const q=JSON.parse('{"title":"css-cqw和cqh","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"src/basics/css/css-cqw和cqh.md","filePath":"src/basics/css/css-cqw和cqh.md","lastUpdated":1764327966000}'),o={name:"src/basics/css/css-cqw和cqh.md"};function t(i,s,r,l,d,p){return n(),e("div",null,s[0]||(s[0]=[c(`<h1 id="css-cqw和cqh" tabindex="-1">css-cqw和cqh <a class="header-anchor" href="#css-cqw和cqh" aria-label="Permalink to &quot;css-cqw和cqh&quot;">​</a></h1><p><code>cqw</code> 和 <code>cqh</code> 是 CSS 中相对较新的单位，属于容器查询（Container Queries）的一部分。它们是为了增强响应式设计的灵活性和控制能力，特别是在设计复杂的布局时。</p><h3 id="_1-什么时候出来的" tabindex="-1">1. <strong>什么时候出来的？</strong> <a class="header-anchor" href="#_1-什么时候出来的" aria-label="Permalink to &quot;1. **什么时候出来的？**&quot;">​</a></h3><p><code>cqw</code> 和 <code>cqh</code> 是随着 <strong>容器查询</strong>（Container Queries）功能的推出而出现的，容器查询是 CSS 4 的一部分，旨在提供基于父容器的尺寸来动态调整元素样式的能力。容器查询在 2021 年左右开始在浏览器中实验性支持，之后逐步完善。</p><h3 id="_2-特性" tabindex="-1">2. <strong>特性</strong> <a class="header-anchor" href="#_2-特性" aria-label="Permalink to &quot;2. **特性**&quot;">​</a></h3><ul><li><code>**cqw**</code>: 是 <strong>container width</strong> 的缩写，表示相对于父容器宽度的单位，类似于 <code>vw</code>（视口宽度单位），但是它是基于父容器宽度来计算的，而不是视口的宽度。</li><li><code>**cqh**</code>: 是 <strong>container height</strong> 的缩写，表示相对于父容器高度的单位，类似于 <code>vh</code>（视口高度单位），但它是基于父容器高度来计算的，而不是视口的高度。</li></ul><h3 id="_3-有什么特性" tabindex="-1">3. <strong>有什么特性？</strong> <a class="header-anchor" href="#_3-有什么特性" aria-label="Permalink to &quot;3. **有什么特性？**&quot;">​</a></h3><ul><li><strong>响应式布局</strong>：这两个单位使得设计师和开发者能够更加精确地控制元素在不同尺寸的容器中的展示效果。例如，可以使某些元素根据容器宽度或高度的变化调整大小，而不是单纯依赖于视口尺寸。</li><li><strong>更细致的控制</strong>：与传统的 <code>vw</code>、<code>vh</code> 或 <code>em</code> 单位不同，<code>cqw</code> 和 <code>cqh</code> 让你可以更加精细地根据父元素的实际尺寸进行调整。</li><li><strong>提高适应性</strong>：它们特别适用于设计具有复杂布局和嵌套容器的网页，提升了设计的灵活性和适应性。</li></ul><h3 id="_4-示例代码" tabindex="-1">4. <strong>示例代码</strong> <a class="header-anchor" href="#_4-示例代码" aria-label="Permalink to &quot;4. **示例代码**&quot;">​</a></h3><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cssCopy Code.container {</span></span>
<span class="line"><span>  width: 100%;</span></span>
<span class="line"><span>  height: 100%;</span></span>
<span class="line"><span>  container-type: inline-size; /* 启用容器查询 */</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>.element {</span></span>
<span class="line"><span>  width: 50cqw; /* 宽度为父容器宽度的50% */</span></span>
<span class="line"><span>  height: 30cqh; /* 高度为父容器高度的30% */</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_5-总结" tabindex="-1">5. <strong>总结</strong> <a class="header-anchor" href="#_5-总结" aria-label="Permalink to &quot;5. **总结**&quot;">​</a></h3><p><code>cqw</code> 和 <code>cqh</code> 通过提供容器相关的单位，极大增强了 CSS 中响应式设计的灵活性和控制力，尤其是在处理具有不规则尺寸或动态调整的容器时。</p>`,12)]))}const g=a(o,[["render",t]]);export{q as __pageData,g as default};
